+import type { ConfigOptions } from "./types.ts";
+import { ConfigParseError } from "./_errors.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  let result: Record<string, unknown> = {};
+  let resolvedPath: string | undefined;
+
+  for (const searchPath of paths) {
+    let found = false;
+    for (const format of formats) {
+      const path = join(searchPath, fileName(options.name, format));
+      const content = await readTextFile(path);
+      if (content === undefined) continue;
+
+      const parsed = parseConfig(content, path, format, options.parser);
+      const values = flattenConfig(parsed);
+      if (!resolvedPath) resolvedPath = path;
+      result = { ...values, ...result };
+      found = true;
+      if (!options.mergeConfigs) return { path: resolvedPath, values: result };
+      break;
+    }
+    if (found && !options.mergeConfigs) break;
+  }
+
+  return { path: resolvedPath, values: result };
+}
+
+function fileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Record<string, unknown> {
+  try {
+    const value = parser ? parser(content) : format === ".json"
+      ? JSON.parse(content)
+      : parseRc(content);
+    if (!isPlainObject(value)) throw new TypeError("Config must be a plain object.");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error instanceof Error ? error.message : error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new TypeError("Expected key=value.");
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
+      value = value.slice(1, -1);
+    }
+    result[key] = coerceRcValue(value);
+  }
+  return result;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) return Number(value);
+  return value;
+}
+
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = camelCase(key);
+    const path = prefix ? `${prefix}.${name}` : name;
+    if (isPlainObject(child)) Object.assign(result, flattenConfig(child, path));
+    else result[path] = child;
+  }
+  return result;
+}
+
+function camelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null && !Array.isArray(value) &&
+    Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function cwd(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  return Deno?.cwd?.() ?? process?.cwd?.() ?? ".";
+}
+
+function join(...parts: string[]): string {
+  return parts.map((part, index) => index ? part.replace(/^[/\\\\]+/, "") : part.replace(/[/\\\\]+$/, "")).join("/");
+}
+
+async function readTextFile(path: string): Promise<string | undefined> {
+  try {
+    // dnt-shim-ignore
+    const { Deno } = globalThis as any;
+    if (Deno) return await Deno.readTextFile(path);
+    const { readFile } = await import("node:fs/promises");
+    return await readFile(path, "utf8");
+  } catch (error) {
+    if (error instanceof Error && ("name" in error) &&
+      ((error as Error).name === "NotFound" || (error as any).code === "ENOENT")) return undefined;
+    throw error;
+  }
+}
